/**
 * StrategyFlowchart — SVG decision tree visualization for strategy logic
 *
 * Parses strategy conditions and renders as a vertical flowchart:
 * Signal → Indicator Check → Entry Condition → Position → Exit Condition
 *
 * Props:
 *   strategy — strategy object with params/parameters, stats, entry_conditions, exit_conditions, indicators
 */
import { RAW as HEX, fonts } from '../tokens';

const NODE_W = 200;
const NODE_H = 40;
const GAP_Y = 28;
const PAD_X = 40;

const COLORS = {
  signal: HEX.blue,
  indicator: HEX.cyan || HEX.cyan,
  entry: HEX.green,
  position: HEX.amber,
  exit: HEX.red,
  risk: HEX.textSecondary,
};

function FlowNode({ x, y, label, detail, color }) {
  return (
    <g>
      <rect
        x={x} y={y} width={NODE_W} height={NODE_H} rx={8}
        fill={`${color}15`} stroke={color} strokeWidth={1.5}
      />
      <text
        x={x + NODE_W / 2} y={y + (detail ? 14 : NODE_H / 2)}
        textAnchor="middle" dominantBaseline="central"
        style={{ fill: color, fontSize: 11, fontWeight: 700, fontFamily: fonts.mono }}
      >
        {label}
      </text>
      {detail && (
        <text
          x={x + NODE_W / 2} y={y + 28}
          textAnchor="middle" dominantBaseline="central"
          style={{ fill: HEX.textSecondary, fontSize: 10, fontFamily: fonts.mono }}
        >
          {detail.length > 30 ? detail.slice(0, 28) + '...' : detail}
        </text>
      )}
    </g>
  );
}

function Connector({ x1, y1, x2, y2 }) {
  const mx = (x1 + x2) / 2;
  const my = (y1 + y2) / 2;
  return (
    <path
      d={`M${x1},${y1} C${x1},${my} ${x2},${my} ${x2},${y2}`}
      fill="none" stroke={HEX.border} strokeWidth={1.5} strokeDasharray="4,3"
    />
  );
}

function Arrow({ x, y1, y2 }) {
  return (
    <>
      <line x1={x} y1={y1} x2={x} y2={y2 - 4} stroke={HEX.border} strokeWidth={1.5} />
      <polygon points={`${x - 4},${y2 - 8} ${x + 4},${y2 - 8} ${x},${y2}`} fill={HEX.border} />
    </>
  );
}

export default function StrategyFlowchart({ strategy }) {
  if (!strategy) return null;

  const params = strategy.params || strategy.parameters || {};
  const stats = strategy.stats || {};

  // Extract strategy components
  const indicators = [];
  const entryConditions = [];
  const exitConditions = [];
  const riskParams = [];

  // Parse indicators from params
  const indicatorKeys = ['sma_period', 'ema_period', 'rsi_period', 'atr_period', 'bb_period',
    'macd_fast', 'macd_slow', 'macd_signal', 'lookback', 'momentum_period', 'vol_lookback'];
  const entryKeys = ['entry_threshold', 'buy_signal', 'entry_condition', 'breakout_pct',
    'pullback_pct', 'volume_multiplier', 'min_volume', 'min_rsi', 'max_rsi'];
  const exitKeys = ['exit_threshold', 'sell_signal', 'exit_condition', 'take_profit',
    'stop_loss', 'trailing_stop', 'max_hold_days', 'profit_target'];
  const riskKeys = ['position_size', 'max_risk_pct', 'stop_loss_pct', 'take_profit_pct',
    'max_positions', 'risk_per_trade'];

  for (const [key, val] of Object.entries(params)) {
    const kl = key.toLowerCase();
    if (indicatorKeys.some(ik => kl.includes(ik.replace('_', '')))) {
      indicators.push({ key, val });
    } else if (entryKeys.some(ek => kl.includes(ek.replace('_', '')))) {
      entryConditions.push({ key, val });
    } else if (exitKeys.some(ek => kl.includes(ek.replace('_', '')))) {
      exitConditions.push({ key, val });
    } else if (riskKeys.some(rk => kl.includes(rk.replace('_', '')))) {
      riskParams.push({ key, val });
    }
  }

  // Also check for explicit conditions arrays
  if (strategy.entry_conditions) {
    (Array.isArray(strategy.entry_conditions) ? strategy.entry_conditions : [strategy.entry_conditions])
      .forEach(c => entryConditions.push({ key: 'condition', val: c }));
  }
  if (strategy.exit_conditions) {
    (Array.isArray(strategy.exit_conditions) ? strategy.exit_conditions : [strategy.exit_conditions])
      .forEach(c => exitConditions.push({ key: 'condition', val: c }));
  }

  // Build nodes
  const nodes = [];
  const cx = PAD_X;
  let cy = 20;

  // Signal node
  nodes.push({
    x: cx, y: cy,
    label: 'SIGNAL',
    detail: strategy.direction ? `Direction: ${strategy.direction}` : (strategy.category || 'Market Signal'),
    color: COLORS.signal,
  });
  cy += NODE_H + GAP_Y;

  // Indicator nodes
  if (indicators.length > 0) {
    nodes.push({
      x: cx, y: cy,
      label: 'INDICATORS',
      detail: indicators.map(i => `${i.key}=${i.val}`).join(', '),
      color: COLORS.indicator,
    });
    cy += NODE_H + GAP_Y;
  }

  // Entry conditions
  if (entryConditions.length > 0) {
    nodes.push({
      x: cx, y: cy,
      label: 'ENTRY',
      detail: entryConditions.map(e => `${e.key}=${e.val}`).join(', '),
      color: COLORS.entry,
    });
  } else {
    nodes.push({ x: cx, y: cy, label: 'ENTRY', detail: 'Signal confirmed', color: COLORS.entry });
  }
  cy += NODE_H + GAP_Y;

  // Position
  nodes.push({
    x: cx, y: cy,
    label: 'POSITION',
    detail: `${strategy.direction || 'Long'} | ${stats.count || '?'} trades`,
    color: COLORS.position,
  });
  cy += NODE_H + GAP_Y;

  // Exit conditions
  if (exitConditions.length > 0) {
    nodes.push({
      x: cx, y: cy,
      label: 'EXIT',
      detail: exitConditions.map(e => `${e.key}=${e.val}`).join(', '),
      color: COLORS.exit,
    });
  } else {
    nodes.push({ x: cx, y: cy, label: 'EXIT', detail: 'Signal reversal / stop', color: COLORS.exit });
  }
  cy += NODE_H + GAP_Y;

  // Risk params (side node)
  if (riskParams.length > 0) {
    nodes.push({
      x: cx, y: cy,
      label: 'RISK',
      detail: riskParams.map(r => `${r.key}=${r.val}`).join(', '),
      color: COLORS.risk,
    });
    cy += NODE_H + GAP_Y;
  }

  const totalH = cy + 10;
  const totalW = NODE_W + PAD_X * 2;

  return (
    <div style={{ overflow: 'auto', maxHeight: 500 }}>
      <svg width="100%" viewBox={`0 0 ${totalW} ${totalH}`} style={{ display: 'block', minHeight: 200 }}>
        {/* Arrows between consecutive nodes */}
        {nodes.map((node, i) => {
          if (i === 0) return null;
          const prev = nodes[i - 1];
          return (
            <Arrow
              key={i}
              x={prev.x + NODE_W / 2}
              y1={prev.y + NODE_H}
              y2={node.y}
            />
          );
        })}

        {/* Nodes */}
        {nodes.map((node, i) => (
          <FlowNode key={i} {...node} />
        ))}
      </svg>
    </div>
  );
}
