const CATEGORY_COLORS = {
  momentum: C.green,
  mean_reversion: C.blue,
  breakout: C.purple,
  short: C.red,
  crypto: C.amber,
};

function TemplateCard({ template, onSelect }) {
  const [hovered, setHovered] = useState(false);
  const catColor = CATEGORY_COLORS[template.category] || C.blue;

  return (
    <div
      onClick={() => onSelect(template.description)}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: hovered ? C.surface2 : C.surface,
        border: `1px solid ${hovered ? catColor + '60' : C.border}`,
        borderRadius: 10,
        padding: 16,
        cursor: 'pointer',
        transition: 'all 0.15s ease',
        transform: hovered ? 'translateY(-2px)' : 'none',
        boxShadow: hovered ? `0 4px 16px ${catColor}15` : 'none',
      }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
        <span style={{
          fontSize: 10, fontWeight: 700, fontFamily: mono, letterSpacing: '0.06em',
          padding: '2px 8px', borderRadius: 6,
          background: catColor + '18', color: catColor, textTransform: 'uppercase',
        }}>
          {CATEGORIES.find(c => c.key === template.category)?.label || template.category}
        </span>
      </div>
      <div style={{
        fontSize: 13, fontWeight: 600, color: C.textPrimary,
        fontFamily: body, marginBottom: 8,
      }}>{template.name}</div>
      <div style={{
        fontSize: 11, color: C.textSecondary, fontFamily: body,
        lineHeight: 1.5, display: '-webkit-box', WebkitLineClamp: 3,
        WebkitBoxOrient: 'vertical', overflow: 'hidden',
      }}>{template.description}</div>
    </div>
  );
}

export default function StrategyTemplateGallery({ onSelect }) {
  const [activeCategory, setActiveCategory] = useState('all');

  const filtered = activeCategory === 'all'
    ? TEMPLATES
    : TEMPLATES.filter(t => t.category === activeCategory);

  return (
    <GlassPanel style={{ padding: 0, overflow: 'hidden' }}>
      <div style={{ padding: '14px 16px 10px' }}>
        <div style={{
          fontSize: 13, fontWeight: 700, color: C.textPrimary,
          fontFamily: body, marginBottom: 12,
        }}>
          Template Gallery
          <span style={{
            fontSize: 10, fontWeight: 500, color: C.textSecondary, marginLeft: 8,
          }}>
            Click a template to populate the builder
          </span>
        </div>

        {/* Category filter pills */}
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          {CATEGORIES.map(cat => (
            <button
              key={cat.key}
              onClick={() => setActiveCategory(cat.key)}
              style={{
                padding: '4px 12px', fontSize: 10, fontWeight: 600, fontFamily: mono,
                borderRadius: 18, cursor: 'pointer',
                background: activeCategory === cat.key ? cat.color + '22' : 'transparent',
                color: activeCategory === cat.key ? cat.color : C.textSecondary,
                border: `1px solid ${activeCategory === cat.key ? cat.color + '50' : C.border}`,
                transition: 'all 0.15s ease',
              }}
            >
              {cat.label}
              {cat.key !== 'all' && (
                <span style={{ marginLeft: 4, opacity: 0.7 }}>
                  ({TEMPLATES.filter(t => t.category === cat.key).length})
                </span>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Template grid */}
      <div style={{
        padding: '4px 16px 16px',
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(210px, 1fr))',
        gap: 12,
        maxHeight: 420,
        overflowY: 'auto',
      }}>
        {filtered.map(t => (
          <TemplateCard key={t.id} template={t} onSelect={onSelect} />
        ))}
      </div>
    </GlassPanel>
  );
}
