// ── Equity Curve (SVG) ────────────────────────────────────────────────────
function EquityCurve({ data }) {
  if (!data || data.length < 2) {
    return (
      <div className={s.equityEmpty}>
        Not enough data points to render equity curve
      </div>
    );
  }

  const W = 760, H = 200, PAD = 40;
  const values = data.map(d => d.value);
  const minV = Math.min(...values);
  const maxV = Math.max(...values);
  const rangeV = maxV - minV || 1;

  const scaleX = (i) => PAD + (i / (data.length - 1)) * (W - PAD * 2);
  const scaleY = (v) => H - PAD - ((v - minV) / rangeV) * (H - PAD * 2);

  const points = data.map((d, i) => `${scaleX(i)},${scaleY(d.value)}`).join(' ');
  const areaPoints = `${scaleX(0)},${H - PAD} ${points} ${scaleX(data.length - 1)},${H - PAD}`;

  const endVal = values[values.length - 1];
  const startVal = values[0];
  const curveColor = endVal >= startVal ? C.green : C.red;

  return (
    <div className={s.equityWrap}>
      <svg viewBox={`0 0 ${W} ${H}`} className={s.equitySvg}>
        {/* Grid lines */}
        {[0.25, 0.5, 0.75].map(pct => {
          const y = PAD + pct * (H - PAD * 2);
          return (
            <line key={pct} x1={PAD} y1={y} x2={W - PAD} y2={y}
              stroke={C.border} strokeWidth={0.5} strokeDasharray="4,4" />
          );
        })}

        {/* Area fill */}
        <polygon points={areaPoints} fill={curveColor} fillOpacity={0.08} />

        {/* Line */}
        <polyline points={points} fill="none" stroke={curveColor}
          strokeWidth={2} strokeLinejoin="round" strokeLinecap="round" />

        {/* Start / end labels */}
        <text x={PAD} y={H - 8} fill={C.textSecondary}
          fontSize={10} fontFamily={mono}>{data[0].date}</text>
        <text x={W - PAD} y={H - 8} fill={C.textSecondary}
          fontSize={10} fontFamily={mono} textAnchor="end">{data[data.length - 1].date}</text>

        {/* Y axis labels */}
        <text x={PAD - 4} y={PAD + 4} fill={C.textSecondary}
          fontSize={10} fontFamily={mono} textAnchor="end">${maxV.toLocaleString()}</text>
        <text x={PAD - 4} y={H - PAD + 4} fill={C.textSecondary}
          fontSize={10} fontFamily={mono} textAnchor="end">${minV.toLocaleString()}</text>
      </svg>
    </div>
  );
}

