// ── Condition Row Builder ─────────────────────────────────────────────────
function ConditionBuilder({ condition, index, onChange, onRemove, type, selectedIndicators }) {
  const indicatorOptions = useMemo(() => {
    const opts = [{ value: 'price', label: 'Price (Close)' }];
    selectedIndicators.forEach(ind => {
      const meta = AVAILABLE_INDICATORS.find(a => a.id === ind.id);
      if (meta) {
        opts.push({ value: ind.id, label: meta.name });
        // Add sub-values for composite indicators
        if (ind.id === 'macd') {
          opts.push({ value: 'macd_histogram', label: 'MACD Histogram' });
          opts.push({ value: 'macd_signal', label: 'MACD Signal Line' });
        }
        if (ind.id === 'bbands') {
          opts.push({ value: 'bbands_upper', label: 'BB Upper' });
          opts.push({ value: 'bbands_lower', label: 'BB Lower' });
          opts.push({ value: 'bbands_middle', label: 'BB Middle' });
        }
        if (ind.id === 'stoch') {
          opts.push({ value: 'stoch_k', label: 'Stochastic %K' });
          opts.push({ value: 'stoch_d', label: 'Stochastic %D' });
        }
      }
    });
    return opts;
  }, [selectedIndicators]);

  const borderColor = type === 'entry' ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)';

  return (
    <div className={s.conditionBuilderRow} style={{
      borderLeft: `3px solid ${borderColor}`,
    }}>
      <div className={s.conditionBuilderInner}>
        <select
          value={condition.indicator || ''}
          onChange={(e) => onChange(index, { ...condition, indicator: e.target.value })}
          className={s.vbSelect}
        >
          <option value="">Select indicator...</option>
          {indicatorOptions.map(opt => (
            <option key={opt.value} value={opt.value}>{opt.label}</option>
          ))}
        </select>

        <select
          value={condition.comparison || ''}
          onChange={(e) => onChange(index, { ...condition, comparison: e.target.value })}
          className={s.vbSelect}
        >
          <option value="">Comparison...</option>
          {COMPARISONS.map(c => (
            <option key={c.value} value={c.value}>{c.label}</option>
          ))}
        </select>

        <select
          value={condition.valueSource || 'fixed'}
          onChange={(e) => onChange(index, { ...condition, valueSource: e.target.value })}
          className={s.vbSelect}
          style={{ maxWidth: 120 }}
        >
          {VALUE_SOURCES.map(vs => (
            <option key={vs.value} value={vs.value}>{vs.label}</option>
          ))}
        </select>

        {condition.valueSource === 'fixed' && (
          <input
            type="number"
            value={condition.value ?? ''}
            onChange={(e) => onChange(index, { ...condition, value: e.target.value === '' ? '' : Number(e.target.value) })}
            placeholder="Value"
            className={s.vbInput}
            style={{ width: 80 }}
          />
        )}

        {condition.valueSource === 'sma' || condition.valueSource === 'ema' ? (
          <input
            type="number"
            value={condition.valuePeriod ?? 20}
            onChange={(e) => onChange(index, { ...condition, valuePeriod: Number(e.target.value) })}
            placeholder="Period"
            className={s.vbInput}
            style={{ width: 60 }}
          />
        ) : null}

        {condition.comparison === 'between' && (
          <input
            type="number"
            value={condition.value2 ?? ''}
            onChange={(e) => onChange(index, { ...condition, value2: e.target.value === '' ? '' : Number(e.target.value) })}
            placeholder="Upper"
            className={s.vbInput}
            style={{ width: 80 }}
          />
        )}
      </div>

      <button onClick={() => onRemove(index)} className={s.conditionRemoveBtn} title="Remove condition">
        &#x2715;
      </button>
    </div>
  );
}

// ── Indicator Config Card ─────────────────────────────────────────────────
function IndicatorConfigCard({ indicator, onChange, onRemove }) {
  const meta = AVAILABLE_INDICATORS.find(a => a.id === indicator.id);
  if (!meta) return null;

  const catColor = CATEGORY_COLORS[meta.category] || C.blue;

  return (
    <div className={s.indicatorConfigCard}>
      <div className={s.indicatorConfigHeader}>
        <span className={s.indicatorConfigName}>
          <span className={s.indicatorConfigDot} style={{ background: catColor }} />
          {meta.name}
        </span>
        <span className={s.indicatorConfigCategory} style={{ color: catColor }}>
          {meta.category}
        </span>
        <button onClick={onRemove} className={s.indicatorConfigRemove} title="Remove">&#x2715;</button>
      </div>
      {meta.params.length > 0 && (
        <div className={s.indicatorConfigParams}>
          {meta.params.map(p => (
            <label key={p.key} className={s.indicatorParamLabel}>
              <span className={s.indicatorParamName}>{p.label}</span>
              <input
                type="number"
                value={indicator.params?.[p.key] ?? p.default}
                onChange={(e) => {
                  const newParams = { ...(indicator.params || {}), [p.key]: Number(e.target.value) };
                  onChange({ ...indicator, params: newParams });
                }}
                className={s.vbInput}
                style={{ width: 70 }}
                step={p.default < 1 ? 0.01 : 1}
              />
            </label>
          ))}
        </div>
      )}
    </div>
  );
}


